"use client";

import { IconSettings } from "@tabler/icons-react";
import { cn } from "@/lib/utils";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import type { PlaybackSpeed } from "@/registry/new-york/speed/types";
import { PLAYBACK_SPEEDS } from "@/registry/new-york/speed/types";

interface YtcnSpeedProps {
  /** Current playback rate */
  playbackRate: number;
  /** Called with the new speed value */
  onSpeedChange: (rate: PlaybackSpeed) => void;
  /**
   * Portal container for fullscreen visibility.
   * Pass containerRef.current to ensure the popover renders inside
   * the fullscreen element rather than document.body.
   */
  containerRef?: React.RefObject<HTMLDivElement | null>;
}

/**
 * YtcnSpeed — Playback speed picker using Radix Popover.
 *
 * Portaled into the player container (via containerRef) so it remains
 * visible in fullscreen mode. Without this, the popover would be
 * appended to document.body and become invisible when the player
 * enters fullscreen.
 */
export function YtcnSpeed({
  playbackRate,
  onSpeedChange,
  containerRef,
}: YtcnSpeedProps) {
  return (
    <Popover>
      <PopoverTrigger asChild>
        <button
          className="flex items-center gap-0.5 rounded-sm px-1.5 py-1 text-xs font-medium text-white transition-colors hover:bg-white/10"
          aria-label="Playback speed"
          onClick={(e) => e.stopPropagation()}
        >
          <IconSettings className="size-4" />
          <span>{playbackRate}x</span>
        </button>
      </PopoverTrigger>
      <PopoverContent
        side="top"
        align="center"
        className="w-auto border-border/50 bg-card/95 p-1 backdrop-blur-md"
        container={containerRef?.current ?? undefined}
      >
        <div className="flex flex-col gap-0.5">
          <p className="px-2 py-1 text-xs text-muted-foreground">Speed</p>
          {PLAYBACK_SPEEDS.map((speed) => (
            <button
              key={speed}
              onClick={() => onSpeedChange(speed)}
              className={cn(
                "rounded-sm px-3 py-1.5 text-left text-sm transition-colors hover:bg-accent",
                playbackRate === speed
                  ? "bg-primary/10 font-semibold text-primary"
                  : "text-foreground"
              )}
            >
              {speed === 1 ? "Normal" : `${speed}x`}
            </button>
          ))}
        </div>
      </PopoverContent>
    </Popover>
  );
}

import type { QualityLevel } from "@/lib/ytcn/quality";

/* ================================================================ */
/*  Playback Speed                                                   */
/* ================================================================ */

export type PlaybackSpeed = 0.25 | 0.5 | 0.75 | 1 | 1.25 | 1.5 | 1.75 | 2;

export const PLAYBACK_SPEEDS: PlaybackSpeed[] = [
  0.25, 0.5, 0.75, 1, 1.25, 1.5, 1.75, 2,
];

/* ================================================================ */
/*  Player State                                                     */
/* ================================================================ */

export interface PlayerState {
  isPlaying: boolean;
  isMuted: boolean;
  volume: number; // 0–100
  currentTime: number; // seconds
  duration: number; // seconds
  loadedFraction: number; // 0–1 buffer progress
  isLoading: boolean;
  isFullscreen: boolean;
  playbackRate: PlaybackSpeed;
  selectedQuality: QualityLevel | "auto";
  actualQuality: QualityLevel | "";
  availableQualities: QualityLevel[];
}

/* ================================================================ */
/*  Player Options                                                   */
/* ================================================================ */

export interface YtcnPlayerOptions {
  /** YouTube video ID (the 11-character string, not a full URL) */
  videoId: string;
  /** Start playback automatically. Browsers require muted audio for this. */
  autoplay?: boolean;
  /** Initial quality hint — applied via both vq and setPlaybackQualityRange */
  defaultQuality?: QualityLevel | "auto";
  /** Initial playback rate */
  defaultSpeed?: PlaybackSpeed;
  /** Resume from this timestamp (seconds) */
  startAt?: number;
  /** Fired when the video reaches its end */
  onEnd?: () => void;
  /** Polled every 250ms during playback */
  onTimeUpdate?: (currentTime: number, duration: number) => void;
  /** Fired when the actual quality level changes */
  onQualityChange?: (quality: string) => void;
  /** Fired when the playback rate changes */
  onPlaybackRateChange?: (rate: number) => void;
}

/* ================================================================ */
/*  Controls Interface                                               */
/* ================================================================ */

export interface PlayerControls {
  play: () => void;
  pause: () => void;
  togglePlay: () => void;
  seekTo: (seconds: number) => void;
  seekRelative: (delta: number) => void;
  setVolume: (vol: number) => void;
  toggleMute: () => void;
  setSpeed: (rate: PlaybackSpeed) => void;
  setQuality: (quality: QualityLevel | "auto") => void;
  toggleFullscreen: () => void;
}

/* ================================================================ */
/*  Keyboard Shortcut Bindings                                       */
/* ================================================================ */

export interface KeyboardBindings {
  play?: string;
  mute?: string;
  fullscreen?: string;
  seekBack?: string;
  seekForward?: string;
}

export const DEFAULT_KEYBOARD_BINDINGS: Required<KeyboardBindings> = {
  play: " ",
  mute: "m",
  fullscreen: "f",
  seekBack: "ArrowLeft",
  seekForward: "ArrowRight",
};
